repo_content.utils.py:
def flatten(lst):
    result = []
    for item in lst:
        if isinstance(item, list):
            result.extend(item)
        else:
            result.append(item)
    return result

repo_content.maxutil.py:
def find_max(lst):
    if not lst:
        return None
    result = lst[0]
    for x in lst[1:]:
        if x < result:
            result = x
    return result

